 func (c *ClaudeDetector) IsInstalled() bool {
-	_, err := exec.LookPath("claude")
-	return err == nil
+	// Use cached result if available
+	if c.cachedInfo != nil && time.Since(c.cacheTime) < c.cacheTTL {
